ModuleRuleTarget.TargetUserLogic:
NVL(
  VAL(&ID, &Module='INVK-PER'                                                 /** Current Assigned Person **/
    and XH:U1=VAL(T:ASSIGNEDPERSON, T:STATUS='WR') 
    and XH:U1!=NULL
  ),
  VAL(&ID, &Module='INVK-TEAM'                                                /** Current Assigned Team **/
    and XH:N1 = VAL(T:ASSIGNEDTEAM, T:STATUS='WR')
    and XH:N1 != NULL 
  )
)

ADD(C18:R1 = XC1:R1;
C18:CB1 = 'Y', &Module = 'INVK-REF' AND &ID != NULL AND &ID = H:R8, XC1:R1 != NULL
AND XC1:R1 NOT IN LIST(C18:R1))

Add(C10:R1=&ID;
 C10:CB1='Y';
C10:P1 = 'INVK-CR01-P1-C10-1'
, &Module='INVK-PER' 
  and &ID = H:R1                                                                   /** Originator **/
  and &ID not in LIST(C10:R1)
)

Add(
C1:CL1= getEventNotes();
C1:D1= &Today;
C1:U1=&PersonID;
C1:CS1='Rollback from '|GetLastSavedValue(H:P1:Meaning)|' to '|H:P1:Meaning;
C1:T1= &Now
)
